/**
 * Create a notification payload and dispatch it through the appropriate adapter.
 * Dispatches are serialized through a queue to preserve delivery ordering —
 * concurrent calls wait for prior dispatches to complete before sending.
 */
async dispatchNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  metadata?: Record<string, unknown>;
}): Promise<Notification> {
  const result = this.dispatchQueue.then(
    () => this.processNotification(params),
    () => this.processNotification(params),
  );
  this.dispatchQueue = result;
  return result;
}

/**
 * Internal: process a single notification dispatch (preference check, adapter send).
 */
private async processNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  metadata?: Record<string, unknown>;
}): Promise<Notification> {
  // Check user preferences before sending (works for all channels)
  if (this.preferencesRepository) {
    const userId = params.metadata?.['userId'] as string | undefined;
    if (userId) {
      const prefs = this.preferencesRepository.findByUserId(userId);
      const channelPrefs = prefs
        ? getChannelPreferences(prefs, params.channel)
        : DEFAULT_EMAIL_PREFERENCES; // default: all-enabled for any channel
      if (!isChannelNotificationEnabled(channelPrefs, params.type)) {
        this.logger.info(
          `Notification ${params.type} via ${params.channel} suppressed for user ${userId} (disabled by preferences)`,
        );
        const payload: NotificationPayload = {
          id: generateNotificationId(),
          type: params.type,
          channel: params.channel,
          recipient: params.recipient,
          subject: params.subject,
          body: params.body,
          priority: params.priority,
          createdAt: new Date(),
          metadata: params.metadata,
        };
        const notification: Notification = {
          payload,
          results: [],
          status: 'failed',
        };
        this.logToHistory(notification);
        return notification;
      }
    }
  }

  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    priority: params.priority,
    createdAt: new Date(),
    metadata: params.metadata,
  };

  const adapter = this.adapters.get(params.channel);
  if (!adapter) {
    this.logger.warn(`No adapter registered for channel: ${params.channel}`);
    const notification: Notification = {
      payload,
      results: [],
      status: 'failed',
    };
    this.notifications.push(notification);
    this.logToHistory(notification);
    return notification;
  }

  const result = await adapter.send(payload);
  const notification: Notification = {
    payload,
    results: [result],
    status: result.success ? 'sent' : 'failed',
  };

  this.notifications.push(notification);
  this.logToHistory(notification);
  this.logger.info(
    `Notification ${payload.id} (${params.type}) via ${params.channel}: ${notification.status}`,
  );

  return notification;
}

